mapper.select:
SELECT id, patient_id, card_no, patient_name, phone, member_type, level_name, total_consume, balance, total_stored, points, open_date, expire_date, status, created_at, updated_at, deleted FROM clinic_member WHERE deleted = 0
AND (patient_name LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%') OR level_name LIKE CONCAT('%', #{keyword}, '%') OR card_no LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE clinic_member
SET deleted = 1, updated_at = NOW()
WHERE id = #{id}
